// Classify Instantly.ai engagement event
const body = $input.first().json.body || $input.first().json;

const eventType = body.event_type || body.type || 'unknown';
const leadEmail = body.lead_email || body.email || '';
const campaignId = body.campaign_id || '';
const timestamp = body.timestamp || new Date().toISOString();
const replyText = body.reply_text || body.body || '';

// Classify reply sentiment
let classification = 'neutral';
let hubspotStage = 'SEQUENCED';

if (eventType === 'replied') {
  const positiveKeywords = ['interested', 'yes', 'sounds good', 'let\'s', 'tell me more', 'schedule', 'available', 'love to', 'would like', 'can we', 'free'];
  const negativeKeywords = ['unsubscribe', 'not interested', 'remove me', 'stop', 'no thanks', 'opt out', 'don\'t contact', 'wrong person'];
  const neutralKeywords = ['out of office', 'ooo', 'on vacation', 'away until'];

  const lowerReply = replyText.toLowerCase();
  if (positiveKeywords.some(k => lowerReply.includes(k))) {
    classification = 'positive';
    hubspotStage = 'MEETING_REQUESTED';
  } else if (negativeKeywords.some(k => lowerReply.includes(k))) {
    classification = 'negative';
    hubspotStage = 'UNSUBSCRIBED';
  } else if (neutralKeywords.some(k => lowerReply.includes(k))) {
    classification = 'neutral_ooo';
    hubspotStage = 'SEQUENCED';
  } else {
    classification = 'neutral';
    hubspotStage = 'REPLIED_NEUTRAL';
  }
} else if (eventType === 'opened') {
  classification = 'opened';
  hubspotStage = 'OPENED';
} else if (eventType === 'bounced') {
  classification = 'bounced';
  hubspotStage = 'BOUNCED';
} else if (eventType === 'clicked') {
  classification = 'clicked';
  hubspotStage = 'CLICKED';
}

return [{
  json: {
    event_type: eventType,
    lead_email: leadEmail,
    campaign_id: campaignId,
    timestamp,
    reply_text: replyText,
    classification,
    hubspot_stage: hubspotStage,
    is_positive: classification === 'positive',
    is_negative: classification === 'negative',
    should_suppress: classification === 'negative' || classification === 'bounced',
    raw_event: body
  }
}];

// Add to suppression list for negative replies and bounces
const event = $input.first().json;

if (!event.should_suppress) {
  return [{ json: { skipped: true, reason: 'not a suppression event' } }];
}

// Store suppressed emails in workflow static data
const staticData = $getWorkflowStaticData('global');
const suppressionList = staticData.suppressionList || [];

const entry = {
  email: event.lead_email,
  reason: event.classification,
  suppressed_at: new Date().toISOString(),
  campaign_id: event.campaign_id
};

// Deduplicate
const alreadySuppressed = suppressionList.some(e => e.email === event.lead_email);
if (!alreadySuppressed) {
  suppressionList.push(entry);
  staticData.suppressionList = suppressionList.slice(-10000); // cap at 10k
}

return [{
  json: {
    suppressed: !alreadySuppressed,
    email: event.lead_email,
    reason: event.classification,
    total_suppressed: suppressionList.length
  }
}];

// Calculate pipeline metrics from HubSpot deals
const deals = $input.all().map(item => item.json);

const now = new Date();
const todayStr = now.toLocaleDateString('en-US', { timeZone: 'America/Los_Angeles' });

// Stage counts
const stageCounts = {};
const tierCounts = { A: 0, B: 0, C: 0, D: 0 };
const signalTypeCounts = {};

for (const deal of deals) {
  const stage = deal.properties?.dealstage || deal.dealstage || 'unknown';
  const tier = deal.properties?.icp_score || deal.icp_score || 'unknown';
  const signalType = deal.properties?.signal_type || deal.signal_type || 'unknown';

  stageCounts[stage] = (stageCounts[stage] || 0) + 1;
  if (tier in tierCounts) tierCounts[tier]++;
  signalTypeCounts[signalType] = (signalTypeCounts[signalType] || 0) + 1;
}

// Funnel metrics
const totalSignals = deals.length;
const qualified = (stageCounts['qualifiedtobuy'] || 0) + (stageCounts['SEQUENCED'] || 0) + (stageCounts['MEETING_REQUESTED'] || 0) + (stageCounts['OPENED'] || 0);
const sequenced = stageCounts['SEQUENCED'] || 0;
const replied = (stageCounts['MEETING_REQUESTED'] || 0) + (stageCounts['REPLIED_NEUTRAL'] || 0);
const meetings = stageCounts['MEETING_REQUESTED'] || 0;
const positiveReplies = stageCounts['MEETING_REQUESTED'] || 0;

// Cost estimates (rough: $0.05/contact enrichment + $0.01/email)
const estimatedCost = (qualified * 0.05) + (sequenced * 0.01);
const costPerMeeting = meetings > 0 ? (estimatedCost / meetings).toFixed(2) : 'N/A';

// Reply rate
const replyRate = sequenced > 0 ? ((replied / sequenced) * 100).toFixed(1) + '%' : '0%';
const openRate = sequenced > 0 ? (((stageCounts['OPENED'] || 0) / sequenced) * 100).toFixed(1) + '%' : '0%';

return [{
  json: {
    date: todayStr,
    timestamp: now.toISOString(),
    total_signals: totalSignals,
    qualified,
    sequenced,
    replied,
    meetings,
    positive_replies: positiveReplies,
    open_rate: openRate,
    reply_rate: replyRate,
    estimated_cost_usd: estimatedCost.toFixed(2),
    cost_per_meeting_usd: costPerMeeting,
    tier_breakdown: tierCounts,
    stage_breakdown: stageCounts,
    signal_type_breakdown: signalTypeCounts
  }
}];
